// Parse meta tags
const aiResponse = $input.first().json.content;
const product = $input.all()[0].json;

let meta;
try {
  meta = JSON.parse(aiResponse);
} catch (e) {
  meta = {
    title_tag: product.title.substring(0, 60),
    meta_description: product.description.substring(0, 160),
    og_title: product.title,
    og_description: product.description.substring(0, 200),
    keywords: product.tags,
    structured_data_type: 'Product'
  };
}

return [{
  json: {
    product_id: product.product_id,
    product_title: product.title,
    title_tag: meta.title_tag,
    meta_description: meta.meta_description,
    og_title: meta.og_title,
    og_description: meta.og_description,
    keywords: meta.keywords,
    structured_data_type: meta.structured_data_type,
    applied: false,
    audit_score: 0,
    timestamp: new Date().toISOString()
  }
}];

